module packet_filtering (  
    input [4:0] src_ip,  
    input [4:0] dest_ip,  
    output reg obf_allowed  
);  
    always @(*) begin  
        if ((src_ip >= 5 && src_ip <= 10) && (dest_ip == 15))  
            obf_allowed = 1;  
        else  
            obf_allowed = 0;  
    end  
endmodule
